/* ============================================================
   RT · Table Order-Line Detail — Helios Dark
   Block-scoped under .wrapper. Yellow primary, pink secondary.
   ============================================================ */

/* ---- block-local token base (extends the active theme, never replaces it) ---- */
.wrapper {
  --rt-surface: var(--block-bg-color, #15151A);
  --rt-raised: #1B1B22;
  --rt-input-bg: var(--input-bg-color, #1B1B21);
  --rt-input-border: var(--input-border-color, var(--color-gray-300, #2A2A32));
  --rt-ink: var(--color-text, #F4F4F7);
  --rt-muted: var(--color-gray-500, #8A8A96);
  --rt-line: var(--color-gray-200, rgba(255,255,255,.07));
  --rt-row-line: rgba(255,255,255,.06);
  --rt-accent: var(--color-primary, #FFD21E);
  --rt-accent-2: var(--color-secondary, #FF3D8B);
  --rt-danger: var(--color-danger, #FF5A6E);
  container-type: inline-size;
  color: var(--rt-ink);
  font-family: var(--font-stack-primary, 'Inter', system-ui, -apple-system, 'Segoe UI', Roboto, sans-serif);
}

/* secondary accent (pink) appears only on text selection — restrained, on-spec */
.wrapper ::selection {
  background: color-mix(in srgb, var(--rt-accent-2) 32%, transparent);
  color: var(--rt-ink);
}

/* ---- card surface ---- */
.wrapper .rt-detail-odl {
  display: flex;
  flex-direction: column;
  gap: 14px;
  background: var(--rt-surface);
  border: 1px solid var(--rt-line);
  border-radius: 14px;
  padding: 16px;
  box-shadow: 0 1px 0 rgba(255,255,255,.03) inset, 0 6px 18px rgba(0,0,0,.5);
}

/* ---- toolbar / heading ---- */
.wrapper .rt-toolbar-odl {
  display: flex;
  flex-wrap: wrap;
  align-items: center;
  gap: 10px 14px;
}
.wrapper .rt-heading-odl {
  display: flex;
  flex-direction: column;
  gap: 4px;
  margin-right: auto;
  min-width: 0;
}
.wrapper .rt-eyebrow-odl {
  font: 700 11px/1.2 var(--font-stack-primary, 'Inter', system-ui, sans-serif);
  letter-spacing: .13em;
  text-transform: uppercase;
  color: var(--rt-ink);
}
.wrapper .rt-eyebrow-odl::before {
  content: "";
  display: inline-block;
  width: 7px;
  height: 7px;
  border-radius: 50%;
  margin-right: 8px;
  background: var(--rt-accent);
  vertical-align: middle;
}
.wrapper .rt-count-odl {
  font: 600 11px/1.3 var(--font-stack-primary, 'Inter', system-ui, sans-serif);
  letter-spacing: .01em;
  color: var(--rt-muted);
  font-variant-numeric: tabular-nums;
}

/* ---- search ---- */
.wrapper .rt-searchwrap-odl {
  display: inline-flex;
  align-items: center;
}
.wrapper .rt-sr-only-odl {
  position: absolute;
  width: 1px;
  height: 1px;
  padding: 0;
  margin: -1px;
  overflow: hidden;
  clip: rect(0 0 0 0);
  white-space: nowrap;
  border: 0;
}
.wrapper .rt-search-odl {
  font: 500 13px/1 var(--font-stack-primary, 'Inter', system-ui, sans-serif);
  padding: 9px 12px;
  min-height: 44px;
  min-width: 240px;
  border-radius: 10px;
  border: 1px solid var(--rt-input-border);
  background: var(--rt-input-bg);
  color: var(--rt-ink);
  caret-color: var(--rt-accent);
  transition: border-color .15s ease;
}
.wrapper .rt-search-odl::placeholder {
  color: var(--rt-muted);
}
.wrapper .rt-search-odl:hover {
  border-color: color-mix(in srgb, var(--rt-accent) 28%, var(--rt-input-border));
}
.wrapper .rt-search-odl:focus-visible {
  outline: 2px solid var(--rt-accent);
  outline-offset: 2px;
  border-color: color-mix(in srgb, var(--rt-accent) 50%, var(--rt-input-border));
}

/* ---- table shell ---- */
.wrapper .rt-tablewrap-odl {
  overflow: auto;
  -webkit-overflow-scrolling: touch;
  overscroll-behavior: contain;
  border: 1px solid var(--rt-line);
  border-radius: 12px;
  max-height: 640px;
  min-width: 0;
}
.wrapper .rt-tablewrap-odl:focus-visible {
  outline: 2px solid var(--rt-accent);
  outline-offset: -2px;
}
.wrapper .rt-table-odl {
  width: 100%;
  border-collapse: collapse;
  font: 500 13px/1.4 var(--font-stack-primary, 'Inter', system-ui, sans-serif);
}

/* ---- sticky header ---- */
.wrapper .rt-thead-odl th {
  position: sticky;
  top: 0;
  z-index: 1;
  background: var(--rt-surface);
  border-bottom: 1px solid var(--rt-line);
  box-shadow: 0 6px 12px -10px rgba(0,0,0,.7);
  padding: 0;
  text-align: left;
  white-space: nowrap;
}
.wrapper .rt-thead-odl th.rt-num-odl {
  text-align: right;
}
.wrapper .rt-th-odl.rt-sorted-odl {
  box-shadow: inset 0 -2px 0 var(--rt-accent), 0 6px 12px -10px rgba(0,0,0,.7);
}
.wrapper .rt-sortbtn-odl {
  display: inline-flex;
  align-items: center;
  gap: 6px;
  width: 100%;
  min-height: 44px;
  background: transparent;
  border: 0;
  cursor: pointer;
  padding: 11px 12px;
  font: 700 11px/1.2 var(--font-stack-primary, 'Inter', system-ui, sans-serif);
  letter-spacing: .04em;
  text-transform: uppercase;
  color: var(--rt-muted);
  transition: color .15s ease;
}
.wrapper .rt-th-odl.rt-num-odl .rt-sortbtn-odl {
  justify-content: flex-end;
}
.wrapper .rt-sortbtn-odl:hover {
  color: var(--rt-ink);
}
.wrapper .rt-sortbtn-odl:active {
  color: var(--rt-accent);
}
.wrapper .rt-sortbtn-odl:focus-visible {
  outline: 2px solid var(--rt-accent);
  outline-offset: -2px;
}
.wrapper .rt-th-odl.rt-sorted-odl .rt-sortbtn-odl {
  color: var(--rt-accent);
  text-shadow: 0 0 12px color-mix(in srgb, var(--rt-accent) 45%, transparent);
}
.wrapper .rt-arrow-odl {
  font-size: 9px;
  line-height: 1;
}

/* ---- body rows ---- */
.wrapper .rt-tbody-odl td {
  padding: 10px 12px;
  border-top: 1px solid var(--rt-row-line);
  color: var(--rt-ink);
  white-space: nowrap;
}
.wrapper .rt-num-odl {
  text-align: right;
  font-variant-numeric: tabular-nums;
}
.wrapper .rt-tbody-odl tr {
  transition: background-color .12s ease;
}
.wrapper .rt-tbody-odl tr:hover td {
  background: var(--rt-raised);
}
.wrapper .rt-neg-odl {
  color: var(--rt-danger);
}

/* ---- empty + pager ---- */
.wrapper .rt-empty-odl {
  margin: 0;
  padding: 32px 12px;
  text-align: center;
  color: var(--rt-muted);
  font: 500 13px/1.4 var(--font-stack-primary, 'Inter', system-ui, sans-serif);
}
.wrapper .rt-pager-odl {
  display: flex;
  align-items: center;
  justify-content: flex-end;
  gap: 12px;
}
.wrapper .rt-pager-odl:empty {
  display: none;
}
.wrapper .rt-pageinfo-odl {
  font: 600 11px/1.2 var(--font-stack-primary, 'Inter', system-ui, sans-serif);
  color: var(--rt-muted);
  font-variant-numeric: tabular-nums;
}
.wrapper .rt-pagebtn-odl {
  font: 600 12px/1 var(--font-stack-primary, 'Inter', system-ui, sans-serif);
  padding: 9px 16px;
  min-height: 44px;
  border-radius: 10px;
  border: 1px solid var(--rt-input-border);
  background: var(--rt-input-bg);
  color: var(--rt-ink);
  cursor: pointer;
  transition: color .15s ease, border-color .15s ease, transform .12s ease;
}
.wrapper .rt-pagebtn-odl:hover:not(:disabled) {
  border-color: color-mix(in srgb, var(--rt-accent) 40%, var(--rt-input-border));
  color: var(--rt-accent);
}
.wrapper .rt-pagebtn-odl:active:not(:disabled) {
  transform: translateY(1px);
}
.wrapper .rt-pagebtn-odl:disabled {
  opacity: .4;
  cursor: default;
}
.wrapper .rt-pagebtn-odl:focus-visible {
  outline: 2px solid var(--rt-accent);
  outline-offset: 2px;
}

/* ---------- responsive: container-query collapse ladder (block-cell width, not viewport) ---------- */
@container (max-width: 720px) {
  .wrapper .rt-detail-odl {
    padding: 14px;
    gap: 12px;
  }
  .wrapper .rt-toolbar-odl {
    gap: 10px;
  }
}
@container (max-width: 640px) {
  .wrapper .rt-searchwrap-odl {
    width: 100%;
  }
  .wrapper .rt-search-odl {
    min-width: 0;
    width: 100%;
    font-size: 16px;
  }
  .wrapper .rt-pager-odl {
    justify-content: space-between;
  }
}
@container (max-width: 420px) {
  .wrapper .rt-detail-odl {
    padding: 12px;
  }
  .wrapper .rt-tbody-odl td,
  .wrapper .rt-sortbtn-odl {
    padding-left: 10px;
    padding-right: 10px;
  }
  .wrapper .rt-pagebtn-odl {
    flex: 1 1 auto;
    text-align: center;
  }
}
@media (prefers-reduced-motion: reduce) {
  .wrapper .rt-sortbtn-odl,
  .wrapper .rt-pagebtn-odl,
  .wrapper .rt-search-odl,
  .wrapper .rt-tbody-odl tr {
    transition: none;
  }
  .wrapper .rt-pagebtn-odl:active:not(:disabled) {
    transform: none;
  }
}
